import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import { addCourse } from "../actions/courseReducer";

function AddCourse() {
  const [name, setName] = useState("");
  const [classId, setClassId] = useState("");
  const [file, setFile] = useState(null);
  const [classes, setClasses] = useState([]);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useEffect(() => {
    fetch("http://localhost:3001/classes")
      .then((res) => res.json())
      .then((data) => setClasses(data))
      .catch((error) => toast.error("Ошибка загрузки классов"));
  }, []);

  async function handleSubmit(e) {
    e.preventDefault();
    let fileData = null;

    if (file) {
      const formData = new FormData();
      formData.append("file", file);
      const response = await fetch("http://localhost:3002/upload", {
        method: "POST",
        body: formData,
      });
      fileData = await response.json();
      if (!response.ok) {
        toast.error("Не удалось загрузить файл");
        return;
      }
    }

    const newCourse = {
      name,
      teacherId: user.id,
      classId: parseInt(classId),
    };

    const response = await fetch("http://localhost:3001/courses", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(newCourse),
    });

    if (response.ok) {
      const course = await response.json();
      if (fileData) {
        await fetch("http://localhost:3001/files", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            courseId: course.id,
            filename: fileData.filename,
            originalName: fileData.originalName,
            path: fileData.filePath,
          }),
        });
      }
      dispatch(addCourse(course));
      toast.success("Курс успешно добавлен!");
      navigate("/courses");
    } else {
      toast.error("Не удалось добавить курс");
    }
  }

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <div className="row justify-content-center">
        <div className="col-md-6">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title text-center mb-4">Добавить курс</h2>
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label">Название курса</label>
                  <input
                    type="text"
                    id="name"
                    className="form-control"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="class" className="form-label">Класс</label>
                  <select
                    id="class"
                    className="form-select"
                    value={classId}
                    onChange={(e) => setClassId(e.target.value)}
                    required
                  >
                    <option value="">-- Выберите класс --</option>
                    {classes.map((cls) => (
                      <option key={cls.id} value={cls.id}>
                        {cls.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="mb-3">
                  <label htmlFor="file" className="form-label">Прикрепить файл (опционально)</label>
                  <input
                    type="file"
                    id="file"
                    className="form-control"
                    onChange={(e) => setFile(e.target.files[0])}
                  />
                </div>
                <button type="submit" className="btn btn-primary w-100">Добавить</button>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AddCourse;
